const employeeData = $fromAI('employee_data', 'Employee record with tenure, performance, engagement, skills, and promotion data', 'object');

const features = {
  tenure_years: employeeData.tenure_years || 0,
  performance_rating: employeeData.performance_rating || 0,
  engagement_score: employeeData.engagement_score || 0,
  months_since_promotion: employeeData.last_promotion_months || 0,
  skill_count: Array.isArray(employeeData.skills) ? employeeData.skills.length : 0
};

const baselineRisk = 0.15;

const shapValues = {
  tenure_years: features.tenure_years < 1 ? 0.25 : features.tenure_years > 5 ? -0.15 : 0.05,
  performance_rating: features.performance_rating < 3 ? -0.20 : features.performance_rating > 4 ? 0.15 : 0,
  engagement_score: features.engagement_score < 50 ? 0.30 : features.engagement_score > 75 ? -0.20 : 0,
  months_since_promotion: features.months_since_promotion > 24 ? 0.25 : features.months_since_promotion > 18 ? 0.10 : -0.05,
  skill_count: features.skill_count < 3 ? 0.15 : features.skill_count > 7 ? -0.10 : 0
};

const totalRisk = baselineRisk + Object.values(shapValues).reduce((a, b) => a + b, 0);
const riskLevel = totalRisk > 0.5 ? 'HIGH' : totalRisk > 0.3 ? 'MEDIUM' : 'LOW';

return {
  risk_score: Math.round(totalRisk * 100) / 100,
  risk_level: riskLevel,
  shap_values: shapValues,
  top_risk_factors: Object.entries(shapValues)
    .filter(([k, v]) => v > 0.1)
    .sort((a, b) => b[1] - a[1])
    .map(([factor, impact]) => ({
      factor,
      impact: Math.round(impact * 100) / 100
    })),
  employee_id: employeeData.employee_id
};

const employees = $input.all();
const skillIndex = {};

employees.forEach(emp => {
  const empData = emp.json;
  const skills = Array.isArray(empData.skills) ? empData.skills : [];
  skillIndex[empData.employee_id] = {
    employee_id: empData.employee_id,
    name: empData.name,
    role: empData.role,
    department: empData.department,
    skills: skills.map(s => s.toLowerCase()),
    skill_count: skills.length,
    tenure: empData.tenure_years,
    performance: empData.performance_rating
  };
});

function calculateSimilarity(skills1, skills2) {
  const set1 = new Set(skills1);
  const set2 = new Set(skills2);
  const intersection = [...set1].filter(x => set2.has(x)).length;
  const union = new Set([...set1, ...set2]).size;
  return union > 0 ? intersection / union : 0;
}

const similarityMatrix = {};
Object.keys(skillIndex).forEach(id1 => {
  similarityMatrix[id1] = {};
  Object.keys(skillIndex).forEach(id2 => {
    if (id1 !== id2) {
      similarityMatrix[id1][id2] = calculateSimilarity(skillIndex[id1].skills, skillIndex[id2].skills);
    }
  });
});

return [{ json: { skill_index: skillIndex, similarity_matrix: similarityMatrix, indexed_at: new Date().toISOString() } }];

const targetEmployeeId = $fromAI('employee_id', 'The employee ID to find similar skill profiles for', 'string');
const topN = $fromAI('top_n', 'Number of similar employees to return', 'number', 5);
const similarityMatrix = $fromAI('similarity_matrix', 'The pre-computed similarity matrix from the analytics dataset', 'object');
const skillIndex = $fromAI('skill_index', 'The skill index from the analytics dataset', 'object');

if (!similarityMatrix || !similarityMatrix[targetEmployeeId]) {
  return {
    error: 'Employee not found or no similarity data available',
    target_employee: targetEmployeeId
  };
}

const similarities = Object.entries(similarityMatrix[targetEmployeeId])
  .map(([empId, score]) => ({
    employee_id: empId,
    similarity_score: Math.round(score * 100) / 100
  }))
  .sort((a, b) => b.similarity_score - a.similarity_score)
  .slice(0, topN);

const results = similarities.map(sim => {
  const emp = skillIndex[sim.employee_id];
  return {
    employee_id: sim.employee_id,
    name: emp.name,
    role: emp.role,
    department: emp.department,
    skills: emp.skills,
    similarity_score: sim.similarity_score,
    tenure: emp.tenure,
    performance: emp.performance
  };
});

return {
  target_employee: targetEmployeeId,
  similar_employees: results,
  search_date: new Date().toISOString()
};
